/**
 * Settlement Service
 *
 * Handles retrieval of settlement reports and related data.
 */

import { apiRequest } from '@/shared/services/apiClient.js';
import logger from '@/shared/utils/logger.js';

/**
 * Get user ID from localStorage for x-user-id header
 * For business contact accounts, returns the business_contact's own user ID (not the business ID),
 * as the settlement endpoint expects the contact's ID. For individual accounts, returns the user ID.
 * This differs from disbursementService which uses the business ID for business contacts.
 */
const getStoredUserId = () => {
  try {
    const raw = localStorage.getItem('userData');
    if (!raw) {
      logger.warn('No userData found in localStorage');
      return null;
    }
    const parsed = JSON.parse(raw);

    // If the logged-in user is a business contact or business member, use their own user id
    // (not the business id), because the settlement API expects the business_contact's ID
    // in the x-user-id header.
    const userType = (parsed?.usertype || parsed?.userType || '').toString().toLowerCase();
    const isBusinessContact = userType === 'business_contact' || userType === 'business';
    const isBusinessMember = userType === 'business_member';

    // For business contacts and business members, use their own user id
    if (isBusinessContact || isBusinessMember) {
      const contactId = parsed?.id || null;

      if (contactId) {
        logger.debug('Using business contact id for x-user-id header (settlement)', { contactId });
        return contactId;
      }

      logger.warn('Business contact detected but no user id found in userData', { parsed });
    }

    // For individual accounts or fallback, use common id fields
    const userId = parsed?.id || parsed?.userId || parsed?.user_id || parsed?.customerId || parsed?.customer_id || null;

    if (!userId) {
      logger.error('No suitable id field found in userData', {
        availableFields: Object.keys(parsed || {}),
        userData: parsed
      });
    } else {
      logger.debug('Retrieved user ID for x-user-id header', { userId });
    }

    return userId;
  } catch (error) {
    logger.warn('Unable to parse stored user data for x-user-id header', { error });
    return null;
  }
};

const buildQueryString = (filters = {}) => {
  const entries = Object.entries(filters).filter(([, value]) => value !== undefined && value !== null && value !== '');
  if (!entries.length) { return ''; }
  const search = new URLSearchParams();
  entries.forEach(([key, value]) => {
    if (Array.isArray(value)) {
      value.forEach((v) => search.append(key, v));
    } else {
      search.append(key, value);
    }
  });
  const qs = search.toString();
  return qs ? `?${qs}` : '';
};

const settlementService = {
  /**
   * Fetches settlement summary and detailed records.
   * @param {Object} [filters] - Optional filters to append as query parameters.
   * @returns {Promise<Object>} Settlement report payload.
   */
  async getSettlementReport(filters = {}) {
    const queryString = buildQueryString(filters);
    // Consumer report endpoint: GET /auth/get-settlements
    const endpoint = `/auth/get-settlements${queryString}`;
    const response = await apiRequest(endpoint, {
      method: 'GET',
    });
    return response;
  },

  /**
   * Retrieves settlement records for the authenticated business from the settlements collection.
   * @param {Object} [filters] - Optional filters such as status, settlement_mode, or pagination params.
   * @returns {Promise<Object>} Settlement records payload.
   */
  async getSettlementRecords(filters = {}) {
    const queryString = buildQueryString(filters);
    // According to Postman: GET /api/admin/settlements
    const endpoint = `/api/admin/settlements${queryString}`;

    const response = await apiRequest(endpoint, {
      method: 'GET',
    });
    return response;
  },

  /**
   * Creates a settlement request for the authenticated user.
   * According to Postman: POST /api/v1/settlements with x-user-id header
   * For business accounts, the business ID is sent in x-user-id header (same as disbursements).
   * @param {Object} settlementData - Settlement request data
   * @param {string} settlementData.settlementType - Type of settlement: "full" or "partial"
   * @param {number} settlementData.amount - Amount to settle (required for partial settlements)
   * @returns {Promise<Object>} API response confirming settlement creation
   */
  async createSettlementRequest(settlementData) {
    // According to Postman: POST {{disbursementBaseurl}}/api/v1/settlements
    // with x-user-id header and body: { "settlementType": "full", "amount": 4 }
    const endpoint = '/api/v1/settlements';

    const headers = {};
    const userId = getStoredUserId();

    if (userId) {
      // For business accounts, this will be the business ID; for individual accounts, the user ID
      headers['x-user-id'] = String(userId);
    } else {
      throw new Error('User ID not found. Please log in again.');
    }

    const response = await apiRequest(endpoint, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        settlementType: settlementData.settlementType,
        amount: Number(settlementData.amount), // Ensure amount is a number
        ...(settlementData.channel && { channel: settlementData.channel }),
      }),
    });

    return response;
  },
};

export default settlementService;

