import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { MetricCard } from '@/shared/components';
import { useToast } from '@/app/providers/ToastContext.jsx';
import settlementService from '@/features/settlements/services/settlementService.js';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { useQuery, useMutation } from '@/shared/hooks';
import { apiRequest } from '@/shared/services/apiClient.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import { useFeeCalculation } from '@/features/disbursements/hooks/useFeeCalculation.js';
import { disbursementService } from '@/features/disbursements/services';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';
import '/styles/pages/Settlements.css';

const formatter = new Intl.NumberFormat('en-GH', {
  style: 'currency',
  currency: 'GHS',
  minimumFractionDigits: 2,
});

// methodLabels will be created inside component to use translations

const methodAccent = {
  MOBILE_MONEY: {
    accent: '#0ea5e9',
    soft: 'rgba(14,165,233,0.15)',
    strong: 'rgba(14,165,233,0.3)',
  },
  BANK: {
    accent: '#6366f1',
    soft: 'rgba(99,102,241,0.15)',
    strong: 'rgba(99,102,241,0.3)',
  },
  MOMO: {
    accent: '#0ea5e9',
    soft: 'rgba(14,165,233,0.15)',
    strong: 'rgba(14,165,233,0.3)',
  },
};

const Settlements = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const { settlementServiceId } = useDisbursementServices();
  const { feeData, setFeeData, isCheckingFee, checkFee } = useFeeCalculation(settlementServiceId);

  const methodLabels = {
    MOBILE_MONEY: t('mobileMoney', { ns: 'settlements' }),
    MOMO: t('mobileMoney', { ns: 'settlements' }),
    BANK: t('bankTransfer', { ns: 'settlements' }),
  };
  const resolveMethodKey = (record) => {
    const methodKey = record?.method || '';
    const accountType = primaryAccount ? formatAccountDisplay(primaryAccount)?.type : null;

    // Prefer the configured settlement destination (where funds go)
    if (accountType) {
      return accountType;
    }

    return methodKey || 'MOBILE_MONEY';
  };

  const [summaryCounts, setSummaryCounts] = useState({ total: 0, momo: 0, bank: 0 });

  // Get wallet balance from localStorage or userData
  const getWalletBalance = () => {
    try {
      // First try tokenService
      const balance = tokenService.getWalletBalance();
      if (balance !== null && balance !== undefined) {
        return parseFloat(balance) || 0;
      }

      // Fallback to userData
      const userData = tokenService.getUserData();
      if (userData?.available_balance !== undefined) {
        return parseFloat(userData.available_balance) || 0;
      }
      if (userData?.wallet_balance !== undefined) {
        return parseFloat(userData.wallet_balance) || 0;
      }

      // Fallback to localStorage directly
      const storedBalance = localStorage.getItem('availableBalance');
      if (storedBalance) {
        return parseFloat(storedBalance) || 0;
      }
      const storedWalletBalance = localStorage.getItem('walletBalance');
      if (storedWalletBalance) {
        return parseFloat(storedWalletBalance) || 0;
      }

      return 0;
    } catch (error) {
      logger.warn('Failed to get wallet balance', { error });
      return 0;
    }
  };

  const [availableBalance, setAvailableBalance] = useState(0);
  const [trueAvailableBalance, setTrueAvailableBalance] = useState(0);

  // Initialize from localStorage if available
  useEffect(() => {
    const storedActual = localStorage.getItem('availableBalance');
    const storedDisplay = localStorage.getItem('walletBalance');
    if (storedActual) {setTrueAvailableBalance(parseFloat(storedActual) || 0);}
    if (storedDisplay) {setAvailableBalance(parseFloat(storedDisplay) || 0);}
    
    // Then refresh from API
    refreshWalletBalance();
  }, []);
  const [settlementType, setSettlementType] = useState('');
  const [requestedAmount, setRequestedAmount] = useState('');
  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [pendingRequest, setPendingRequest] = useState(null);
  const [settlementAccounts, setSettlementAccounts] = useState([]);
  const [isRefreshingBalance, setIsRefreshingBalance] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const refreshWalletBalance = useCallback(async () => {
    setIsRefreshingBalance(true);
    try {
      const response = await apiRequest('/auth/get-dashboard-metrics', {
        method: 'GET',
      });
      const data = response?.code === '00' ? response.data : response?.data;
      const displayBal = parseFloat(data?.wallet_balance);
      const actualBal = parseFloat(data?.available_balance ?? data?.wallet_balance);
      
      if (!Number.isNaN(displayBal)) {
        setAvailableBalance(displayBal);
        setTrueAvailableBalance(actualBal);
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem('availableBalance', actualBal.toString());
          localStorage.setItem('walletBalance', displayBal.toString());
        }
        return { displayBal, actualBal };
      }
    } catch (error) {
      logger.warn('Failed to refresh wallet balance', { error });
    } finally {
      setIsRefreshingBalance(false);
    }
    return null;
  }, []);

  const parseCount = (value) => {
    if (value === undefined || value === null || value === '') {return 0;}
    const num = Number(value);
    return Number.isNaN(num) ? 0 : num;
  };

  const toTitleCase = (value) =>
    value
      .toString()
      .toLowerCase()
      .replace(/(^|\s|[-_])([a-z])/g, (_, separator, char) =>
        separator ? separator.replace(/[_-]/g, ' ') + char.toUpperCase() : char.toUpperCase()
      )
      .replace(/\s+/g, ' ')
      .trim();

  const normalizeRecord = (item) => {
    if (!item) {return null;}

    const methodRaw = (
      item.method ??
      item.channel ??
      item.channelFilter ??
      item.channel_filter ??
      item.settlement_channel ??
      ''
    ).toString();
    let methodKey = methodRaw
      ? methodRaw.toUpperCase().replace(/\s+/g, '_')
      : 'MOBILE_MONEY';

    if (methodKey === 'MOMO') {
      methodKey = 'MOBILE_MONEY';
    } else if (methodKey === 'NON_MOMO' || methodKey === 'NON-MOMO') {
      methodKey = 'BANK';
    }

    const amountSource =
      item.amount ?? item.totalAmount ?? item.total_amount ?? item.value ?? 0;
    const amount = Number(amountSource) || 0;

    const chargeSource =
      item.charge ??
      item.charges ??
      item.fee ??
      item.fees ??
      item.total_charges ??
      0;
    const charges = Number(chargeSource) || 0;

    const netSource =
      item.netAmount ?? item.net ?? item.net_amount ?? amount - charges;
    const parsedNet = Number(netSource);
    const netAmount = Number.isNaN(parsedNet) ? amount - charges : parsedNet;

    const rawDate =
      item.date ||
      item.createdAt ||
      item.updatedAt ||
      item.created_at ||
      item.updated_at ||
      item.completed_at ||
      '';
    let formattedDate = rawDate;
    const parsedDate =
      rawDate && typeof rawDate === 'string' ? new Date(rawDate) : null;
    if (parsedDate && !Number.isNaN(parsedDate.getTime())) {
      formattedDate = parsedDate.toISOString().slice(0, 10);
    }

    const typeRaw = (
      item.type ??
      item.settlementType ??
      item.settlement_type ??
      item.settlementMode ??
      item.settlement_mode ??
      item.mode ??
      ''
    ).toString();
    let settlementType = 'Full';
    if (typeRaw) {
      const normalizedType = typeRaw.toLowerCase();
      if (normalizedType === 'partial') {
        settlementType = 'Partial';
      } else if (normalizedType === 'full') {
        settlementType = 'Full';
      } else {
        settlementType = toTitleCase(typeRaw);
      }
    }
    // Note: Status and settlementType will be translated in the render using t() function

    const statusRaw = (
      item.status ??
      item.state ??
      item.settlementStatus ??
      item.settlement_status ??
      item.data?.status ??
      'Completed'
    ).toString();
    const statusLower = statusRaw.toLowerCase();
    let status = statusRaw.charAt(0).toUpperCase() + statusRaw.slice(1).toLowerCase();
    // Map common status values to translation keys
    if (statusLower === 'pending') {
      status = 'Pending';
    } else if (statusLower === 'completed' || statusLower === 'success') {
      status = 'Completed';
    }

    const reference =
      item.reference ||
      item.transactionReference ||
      item.transactionId ||
      item.id ||
      '—';

    const recordId =
      item.id ||
      reference ||
      `${formattedDate}-${methodKey}-${Math.random().toString(36).slice(2, 10)}`;

    return {
      id: recordId,
      reference,
      date: formattedDate || '—',
      method: methodKey,
      amount,
      charges,
      net: netAmount,
      status,
      settlementType,
      settlementMode:
        item.settlementMode ||
        item.settlement_mode ||
        item.mode ||
        '',
    };
  };

  const mergeRecords = (primary = [], secondary = []) => {
    const merged = new Map();

    [...primary, ...secondary].forEach((record) => {
      if (!record) {return;}
      const key = record.reference || record.id;
      const existing = merged.get(key);
      merged.set(key, existing ? { ...existing, ...record } : record);
    });

    return Array.from(merged.values()).sort((a, b) => {
      const aDate = Date.parse(a.date);
      const bDate = Date.parse(b.date);
      if (!Number.isNaN(bDate) && !Number.isNaN(aDate)) {
        return bDate - aDate;
      }
      return 0;
    });
  };

  // Fetch settlement accounts
  const { data: accountsData } = useQuery({
    queryKey: ['settlement-accounts'],
    endpoint: '/api/auth/profile/settlement-account',
    enabled: true,
    staleTime: 5 * 60 * 1000, // 5 minutes
    select: (response) => {
      const accounts = response?.data ?? [];
      return Array.isArray(accounts) ? accounts : [];
    },
    onError: (err) => {
      logger.warn('Failed to fetch settlement accounts', { error: err });
      setSettlementAccounts([]);
    },
  });

  // Update settlement accounts when data changes
  useEffect(() => {
    if (accountsData) {
      setSettlementAccounts(accountsData);
    }
  }, [accountsData]);

  // Use React Query to fetch settlement data with automatic caching and refetching
  // Consumer endpoint: GET /auth/get-settlements
  const { data: settlementData, isLoading, error: loadError, refetch: refetchSettlements } = useQuery({
    queryKey: queryKeys.settlements.all(),
    endpoint: '/auth/get-settlements',
    enabled: true,
    staleTime: 0,
    refetchOnWindowFocus: true,
    refetchOnMount: true,
    select: (response) => {
      // New envelope: { code, data: { data: [...], summary: { totalAmount, totalTransactions }, pagination } }

      let summary = {};
      let reportRecords = [];

      try {
        const payload = response?.data ?? response ?? {};
        // data.data holds the row array; data.summary holds totals
        const rowSource = payload?.data ?? [];
        summary = payload?.summary ?? {};

        if (Array.isArray(rowSource)) {
          reportRecords = rowSource
            .map(normalizeRecord)
            .filter(Boolean);
        }
      } catch (error) {
        throw new Error(t('failedToFetchData', { ns: 'settlements' }));
      }

      const mergedRecords = reportRecords;

      const completedRecords = mergedRecords.filter(r => r.status === 'Completed');
      const counts = {
        total: completedRecords.length,
        momo: completedRecords.filter(
          (record) => record.method === 'MOBILE_MONEY' || record.method === 'MOMO'
        ).length,
        bank: completedRecords.filter((record) => record.method === 'BANK').length,
      };

      // summary.totalAmount from API = sum of successful rows
      // Break down by method from the normalised rows for mobile/bank cards
      const completedMomoAmount = completedRecords
        .filter(r => r.method === 'MOBILE_MONEY' || r.method === 'MOMO')
        .reduce((sum, r) => sum + (Number(r.amount) || 0), 0);
      const completedBankAmount = completedRecords
        .filter(r => r.method === 'BANK')
        .reduce((sum, r) => sum + (Number(r.amount) || 0), 0);

      return {
        records: mergedRecords,
        summaryCounts: counts,
        summaryAmounts: {
          total: Number(summary?.totalAmount || 0),
          mobile: completedMomoAmount,
          bank: completedBankAmount,
        }
      };
    },
    onError: (err) => {
      const message =
        err instanceof Error
          ? err.message
          : t('failedToFetchData', { ns: 'settlements' });
      showError(message);
      setSummaryCounts({ total: 0, momo: 0, bank: 0 });
    },
  });

  useEffect(() => {
    const handleAuthRefresh = () => {
      if (typeof refetchSettlements === 'function') {
        refetchSettlements();
      }
    };

    window.addEventListener('authStateChanged', handleAuthRefresh);
    return () => {
      window.removeEventListener('authStateChanged', handleAuthRefresh);
    };
  }, [refetchSettlements]);

  const records = settlementData?.records || [];

  // Create settlement mutation
  const createSettlementMutation = useMutation({
    mutationFn: async (settlementData) => {
      // Settlement service handles user/business ID retrieval internally (same as disbursements)
      return await settlementService.createSettlementRequest(settlementData);
    },
    invalidateQueries: [
      queryKeys.settlements.all(),
    ],
    onSuccess: (data) => {
      success(t('settlementRequestRaised', { ns: 'settlements' }));
      resetForm();
      // Update wallet balance if returned in response
      if (data?.data?.available_balance !== undefined || data?.data?.wallet_balance !== undefined) {
        const actualBal = parseFloat(data.data.available_balance ?? data.data.wallet_balance) || 0;
        const displayBal = parseFloat(data.data.wallet_balance ?? data.data.available_balance) || 0;
        setAvailableBalance(displayBal);
        setTrueAvailableBalance(actualBal);
        // Update localStorage if needed
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem('availableBalance', actualBal.toString());
          localStorage.setItem('walletBalance', displayBal.toString());
        }
      }
    },
    onError: (error) => {
      const errorMessage = error?.message || t('failedToCreateSettlement', { ns: 'settlements', defaultValue: 'Failed to create settlement request. Please try again.' });
      showError(errorMessage);
    },
  });

  // Update summary counts when data changes
  useEffect(() => {
    if (settlementData?.summaryCounts) {
      setSummaryCounts(settlementData.summaryCounts);
    }
  }, [settlementData]);

  // Update wallet balance when component mounts or when it changes in localStorage
  useEffect(() => {
    const updateWalletBalance = () => {
      const balance = getWalletBalance();
      setAvailableBalance(balance);
    };

    // Initial load
    updateWalletBalance();

    // Listen for storage changes (in case wallet balance is updated elsewhere)
    const handleStorageChange = (e) => {
      if (e.key === 'walletBalance' || e.key === 'availableBalance' || e.key === 'userData') {
        updateWalletBalance();
      }
    };

    window.addEventListener('storage', handleStorageChange);

    // Also listen for custom events if wallet balance is updated via tokenService
    const handleWalletUpdate = () => {
      updateWalletBalance();
    };

    window.addEventListener('walletBalanceUpdated', handleWalletUpdate);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
      window.removeEventListener('walletBalanceUpdated', handleWalletUpdate);
    };
  }, []);

  const totals = useMemo(() => {
    // If API provided summary amounts, use them as they are pre-calculated for 'COMPLETED' only
    if (settlementData?.summaryAmounts && (settlementData.summaryAmounts.total > 0)) {
      return settlementData.summaryAmounts;
    }

    // Fallback: manually aggregate only completed records
    return records.reduce(
      (acc, record) => {
        // Use normalized status 'Completed' (from normalizeRecord)
        if (record.status === 'Completed') {
          const amount = Number(record.amount) || 0;
          acc.total += amount;
          if (record.method === 'MOBILE_MONEY' || record.method === 'MOMO') {
            acc.mobile += amount;
          } else if (record.method === 'BANK') {
            acc.bank += amount;
          }
        }
        return acc;
      },
      { total: 0, mobile: 0, bank: 0 }
    );
  }, [records, settlementData?.summaryAmounts]);

  const summaryCards = useMemo(() => {
    const totalSettlements =
      summaryCounts.total || records.length || 0;
    const mobileSettlements =
      summaryCounts.momo ||
      records.filter((r) => r.method === 'MOBILE_MONEY' || r.method === 'MOMO')
        .length;
    const bankSettlements =
      summaryCounts.bank ||
      records.filter((r) => r.method === 'BANK').length;

    return [
      {
        title: t('totalSettlements', { ns: 'settlements' }),
        value: formatter.format(totals.total),
        hint: '',
        accent: '#0ea5e9',
        soft: 'rgba(14,165,233,0.12)',
        strong: 'rgba(14,165,233,0.32)',
        icon: 'paid',
      },
      {
        title: t('mobileMoneySettlements', { ns: 'settlements' }),
        value: formatter.format(totals.mobile),
        hint: '',
        accent: '#22c55e',
        soft: 'rgba(34,197,94,0.12)',
        strong: 'rgba(34,197,94,0.32)',
        icon: 'smartphone',
      },
      {
        title: t('bankSettlements', { ns: 'settlements' }),
        value: formatter.format(totals.bank),
        hint: '',
        accent: '#6366f1',
        soft: 'rgba(99,102,241,0.12)',
        strong: 'rgba(99,102,241,0.32)',
        icon: 'account_balance',
      },
    ];
  }, [records, summaryCounts, totals, t]);

  const resetForm = () => {
    setSettlementType('');
    setRequestedAmount('');
    setPendingRequest(null);
    setIsConfirmOpen(false);
  };

  useEffect(() => {
    if (settlementType === 'full' && !requestedAmount) {
      setRequestedAmount(availableBalance ? String(availableBalance) : '');
    }
  }, [availableBalance, settlementType, requestedAmount]);

  // Get primary settlement account info
  const primaryAccount = useMemo(() => {
    if (!settlementAccounts || settlementAccounts.length === 0) {return null;}
    
    // Prefer bank account, then mobile money
    const bankAccount = settlementAccounts.find(acc => 
      acc.channel === 'BANK' ||
      acc.channel === 'Bank' ||
      acc.channel === 'bank' ||
      acc.payment_details?.account_type === 'bank'
    );
    if (bankAccount) {return bankAccount;}
    
    const momoAccount = settlementAccounts.find(acc => 
      acc.channel === 'MOMO' ||
      acc.channel === 'MOBILE_MONEY' ||
      acc.channel === 'Mobile Money' ||
      acc.payment_details?.account_type === 'momo' ||
      acc.payment_details?.account_type === 'mobile_money'
    );
    return momoAccount || settlementAccounts[0];
  }, [settlementAccounts]);

  // Format account display
  const formatAccountDisplay = (account) => {
    if (!account) {return null;}
    
    const channel = account.channel || '';
    const normalizedChannel = channel.toString().toUpperCase().replace(/\s+/g, '_');
    const paymentDetails = account.payment_details || {};
    const accountType = (paymentDetails.account_type || '').toString().toLowerCase();
    
    if (normalizedChannel === 'BANK' || accountType === 'bank') {
      return {
        type: 'BANK',
        label: t('bankTransfer', { ns: 'settlements' }),
        details: paymentDetails.bank_name 
          ? `${paymentDetails.bank_name} - ${paymentDetails.account_number || ''}`
          : t('bankAccount', { ns: 'settlements', defaultValue: 'Bank Account' }),
      };
    } else if (normalizedChannel === 'MOMO' || normalizedChannel === 'MOBILE_MONEY' || accountType === 'momo' || accountType === 'mobile_money') {
      return {
        type: 'MOMO',
        label: t('mobileMoney', { ns: 'settlements' }),
        details: paymentDetails.account_number 
          ? `${paymentDetails.network || ''} ${paymentDetails.account_number}`.trim()
          : t('mobileMoneyAccount', { ns: 'settlements', defaultValue: 'Mobile Money Account' }),
      };
    }
    
    return {
      type: channel,
      label: channel,
      details: t('settlementAccount', { ns: 'settlements', defaultValue: 'Settlement Account' }),
    };
  };

  const resolveSettlementChannel = (account) => {
    if (!account) {return null;}
    const channel = (account.channel || '').toString().toUpperCase();
    const accountType = (account.payment_details?.account_type || '').toString().toLowerCase();
    if (channel === 'BANK' || accountType === 'bank') {
      return 'BANK';
    }
    if (channel === 'MOMO' || channel === 'MOBILE_MONEY' || accountType === 'momo' || accountType === 'mobile_money') {
      return 'MOMO';
    }
    return null;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (isSubmitting) return;

    const parsedAmount = settlementType === 'full'
      ? Number(trueAvailableBalance)
      : Number(requestedAmount);

    if (!settlementType) {
      showError(t('selectSettlementType', { ns: 'settlements', defaultValue: 'Select settlement type' }));
      return;
    }

    if (!parsedAmount || Number.isNaN(parsedAmount) || parsedAmount <= 0) {
      showError(t('enterValidAmount', { ns: 'settlements' }));
      return;
    }

    if (parsedAmount > trueAvailableBalance) {
      showError(t('amountExceedsBalance', { ns: 'settlements' }));
      return;
    }

    setIsSubmitting(true);

    // Calculate fee inline at confirm time rather than on every amount change
    let resolvedFeeData = null;

    if (settlementServiceId && primaryAccount) {
      const channel = resolveSettlementChannel(primaryAccount);
      if (channel) {
        try {
          const response = await disbursementService.checkFullPayable({
            amount: parsedAmount.toString(),
            channel,
            serviceId: settlementServiceId,
          });

          if (response.code === '00' && response.data) {
            resolvedFeeData = response.data;
            // Keep feeData state in sync for display purposes
            setFeeData(response.data);
          }
        } catch (err) {
          logger.error('Failed to check fee in handleSubmit:', { error: err });
        }
      }
    }

    setIsSubmitting(false);

    // If fee check failed and service is configured, block submission
    if (!resolvedFeeData && settlementServiceId) {
      showError(t('feeUnavailable', { ns: 'settlements', defaultValue: 'Unable to calculate fee. Please try again.' }));
      return;
    }

    // Fall back to zero fee when service is not configured on this env
    const charges = Number(resolvedFeeData?.feeApplied || resolvedFeeData?.fee || 0);
    const netAmount = parsedAmount - charges;

    const accountDisplay = formatAccountDisplay(primaryAccount);
    setPendingRequest({
      settlementType,
      method: accountDisplay?.type || 'MOBILE_MONEY',
      amount: parsedAmount,
      charges,
      net: netAmount,
    });
    setIsConfirmOpen(true);
  };

  const handleConfirm = async () => {
    if (!pendingRequest) {return;}

    const channel = resolveSettlementChannel(primaryAccount);

    // Prepare settlement data for API
    const settlementData = {
      settlementType: pendingRequest.settlementType === 'partial' ? 'partial' : 'full',
      amount: pendingRequest.settlementType === 'partial' ? pendingRequest.amount : availableBalance,
      ...(channel && { channel }),
    };

    // Call the API to create settlement
    createSettlementMutation.mutate(settlementData);
  };

  const handleCancelConfirmation = () => {
    setIsConfirmOpen(false);
    setPendingRequest(null);
  };

  return (
    <div className="settlements-page">
      <div className="settlement-summary" data-tour="settlements-summary">
        {summaryCards.map((card) => (
          <MetricCard
            key={card.title}
            title={card.title}
            value={card.value}
            hint={card.hint}
            icon={card.icon}
            accent={card.accent}
            accentSoft={card.soft}
            accentStrong={card.strong}
          />
        ))}
      </div>

      <div className="settlement-body">
        <section className="settlement-card" data-tour="settlements-history">
          <div className="settlement-card__header">
            <h3>{t('settlementHistory', { ns: 'settlements' })}</h3>
            <span>
              {isLoading
                ? t('loading', { ns: 'settlements' })
                : t('totalRecords', { ns: 'settlements', count: summaryCounts.total || records.length })}
            </span>
          </div>

          {/* Desktop Table View */}
          <div className="settlement-table-wrapper">
            <table className="settlements-table">
              <thead>
                <tr>
                  <th>{t('reference', { ns: 'settlements' })}</th>
                  <th>{t('date', { ns: 'settlements' })}</th>
                  <th>{t('method', { ns: 'settlements' })}</th>
                  <th>{t('type', { ns: 'settlements' })}</th>
                  <th>{t('amount', { ns: 'settlements' })}</th>
                  <th>{t('status', { ns: 'settlements', defaultValue: 'Status' })}</th>
                </tr>
              </thead>
              <tbody>
                {isLoading ? (
                  <tr>
                    <td colSpan="6" className="settlement-table-empty">
                      {t('fetchingRecords', { ns: 'settlements' })}
                    </td>
                  </tr>
                ) : loadError ? (
                  <tr>
                    <td colSpan="6" className="settlement-table-empty settlement-table-error">
                      {loadError}
                    </td>
                  </tr>
                ) : records.length === 0 ? (
                  <tr>
                    <td colSpan="6" className="settlement-table-empty">
                      {t('noRecordsAvailable', { ns: 'settlements' })}
                    </td>
                  </tr>
                ) : (
                  records.map((record, index) => (
                    <tr key={record.id || `${record.reference}-${index}` || `settlement-${index}`}>
                      <td>{record.reference}</td>
                      <td>{record.date}</td>
                      <td>
                        {(() => {
                          const methodKey = resolveMethodKey(record);
                          return (
                            <span
                              className={`settlement-method settlement-method--${methodKey.toLowerCase()}`}
                            >
                              {methodLabels[methodKey] || methodKey}
                            </span>
                          );
                        })()}
                      </td>
                      <td>
                        {record.settlementType === 'Partial'
                          ? t('partial', { ns: 'settlements' })
                          : t('full', { ns: 'settlements' })}
                      </td>
                      <td>{formatter.format(record.amount)}</td>
                      <td>
                        <span className={`status-badge status-${record.status?.toLowerCase() || 'pending'}`}>
                          {record.status}
                        </span>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Mobile Card View */}
          <div className="settlement-cards-mobile">
            {isLoading ? (
              <div className="settlement-card-mobile settlement-card-empty">
                {t('fetchingRecords', { ns: 'settlements' })}
              </div>
            ) : loadError ? (
              <div className="settlement-card-mobile settlement-card-error">
                {loadError}
              </div>
            ) : records.length === 0 ? (
              <div className="settlement-card-mobile settlement-card-empty">
                {t('noRecordsAvailable', { ns: 'settlements' })}
              </div>
            ) : (
              records.map((record, index) => (
                <div key={record.id || `${record.reference}-${index}` || `settlement-${index}`} className="settlement-card-mobile">
                  <div className="settlement-card-mobile__header">
                    <div className="settlement-card-mobile__reference">{record.reference}</div>
                  </div>
                  <div className="settlement-card-mobile__body">
                    <div className="settlement-card-mobile__row">
                      <span className="settlement-card-mobile__label">{t('date', { ns: 'settlements' })}</span>
                      <span className="settlement-card-mobile__value">{record.date}</span>
                    </div>
                    <div className="settlement-card-mobile__row">
                      <span className="settlement-card-mobile__label">{t('method', { ns: 'settlements' })}</span>
                      {(() => {
                        const methodKey = resolveMethodKey(record);
                        return (
                          <span
                            className={`settlement-method settlement-method--${methodKey.toLowerCase()}`}
                          >
                            {methodLabels[methodKey] || methodKey}
                          </span>
                        );
                      })()}
                    </div>
                    <div className="settlement-card-mobile__row">
                      <span className="settlement-card-mobile__label">{t('type', { ns: 'settlements' })}</span>
                      <span className="settlement-card-mobile__value">
                        {record.settlementType === 'Partial'
                          ? t('partial', { ns: 'settlements' })
                          : t('full', { ns: 'settlements' })}
                      </span>
                    </div>
                    <div className="settlement-card-mobile__row">
                      <span className="settlement-card-mobile__label">{t('status', { ns: 'settlements', defaultValue: 'Status' })}</span>
                      <span className="settlement-card-mobile__value">
                        <span className={`status-badge status-${record.status?.toLowerCase() || 'pending'}`}>
                          {record.status}
                        </span>
                      </span>
                    </div>
                  </div>
                  <div className="settlement-card-mobile__footer">
                      <span className="settlement-card-mobile__label">{t('amount', { ns: 'settlements' })}</span>
                      <span className="settlement-card-mobile__value settlement-card-mobile__amount">
                        {formatter.format(record.amount)}
                      </span>
                  </div>
                </div>
              ))
            )}
          </div>
        </section>

        <aside className="settlement-card settlement-form-card" data-tour="settlements-request">
          <div className="settlement-card__header">
            <h3>{t('raiseSettlementRequest', { ns: 'settlements' })}</h3>
          </div>

          <div className="balance-breakdown">
            <div className="balance-breakdown__item">
              <span className="balance-breakdown__label">{t('walletBalance', { ns: 'settlements', defaultValue: 'Wallet Balance' })}</span>
              <span className="balance-breakdown__value">{formatter.format(availableBalance)}</span>
            </div>
            {availableBalance > trueAvailableBalance && (
              <div className="balance-breakdown__item">
                <span className="balance-breakdown__label">{t('heldFunds', { ns: 'settlements', defaultValue: 'Held in Processing' })}</span>
                <span className="balance-breakdown__value" style={{ color: 'var(--error)' }}>
                  -{formatter.format(availableBalance - trueAvailableBalance)}
                </span>
              </div>
            )}
            <div className="balance-breakdown__item balance-breakdown__item--total">
              <span className="balance-breakdown__label">{t('availableToSettle', { ns: 'settlements' })}</span>
              <span className="balance-breakdown__value">{formatter.format(trueAvailableBalance)}</span>
            </div>
          </div>

          <div className="payout-type-selector">
            <button
              type="button"
              className={`payout-type-option ${settlementType === 'full' ? 'payout-type-option--active' : ''}`}
              onClick={async () => {
                setSettlementType('full');
                const balanceResult = await refreshWalletBalance();
                const nextAmount = balanceResult ? balanceResult.actualBal : trueAvailableBalance;
                setRequestedAmount(nextAmount ? String(nextAmount) : '');
              }}
            >
              {t('fullPayout', { ns: 'settlements' })}
            </button>
            <button
              type="button"
              className={`payout-type-option ${settlementType === 'partial' ? 'payout-type-option--active' : ''}`}
              onClick={() => {
                setSettlementType('partial');
                setRequestedAmount('');
              }}
            >
              {t('partialPayout', { ns: 'settlements' })}
            </button>
          </div>

          <form className="settlement-form" onSubmit={handleSubmit}>
            <div className="settlement-input-group">
              <label className="settlement-label" style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginBottom: '8px', display: 'block' }}>
                {t('amountToSettle', { ns: 'settlements', defaultValue: 'Amount to Settle' })}
              </label>

              {/* Full payout — read-only display of available balance */}
              {settlementType === 'full' ? (
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '0',
                  border: '2px solid var(--border-primary)',
                  borderRadius: 'var(--radius-xl)',
                  overflow: 'hidden',
                  backgroundColor: 'var(--bg-tertiary)',
                }}>
                  <span style={{
                    padding: '16px 14px',
                    fontSize: '1rem',
                    fontWeight: 700,
                    color: 'var(--text-muted)',
                    backgroundColor: 'var(--bg-secondary, var(--bg-tertiary))',
                    borderRight: '1px solid var(--border-primary)',
                    flexShrink: 0,
                    lineHeight: 1,
                  }}>
                    GHS
                  </span>
                  <span style={{
                    flex: 1,
                    padding: '16px',
                    fontSize: '1.25rem',
                    fontWeight: 700,
                    color: 'var(--text-muted)',
                    cursor: 'not-allowed',
                    userSelect: 'none',
                  }}>
                    {trueAvailableBalance ? Number(trueAvailableBalance).toFixed(2) : '0.00'}
                  </span>
                  <span style={{
                    padding: '16px 14px',
                    fontSize: '0.75rem',
                    fontWeight: 600,
                    color: 'var(--text-muted)',
                    flexShrink: 0,
                  }}>
                    Full
                  </span>
                </div>
              ) : (
                /* Partial payout — editable input with GHS prefix */
                <div style={{
                  display: 'flex',
                  alignItems: 'stretch',
                  border: `2px solid ${settlementType === 'partial' ? 'var(--border-primary)' : 'var(--border-secondary)'}`,
                  borderRadius: 'var(--radius-xl)',
                  overflow: 'hidden',
                  backgroundColor: settlementType ? 'var(--bg-input)' : 'var(--bg-tertiary)',
                  transition: 'border-color 0.2s ease',
                }}
                onFocusCapture={(e) => e.currentTarget.style.borderColor = 'var(--accent)'}
                onBlurCapture={(e) => e.currentTarget.style.borderColor = 'var(--border-primary)'}
                >
                  <span style={{
                    padding: '16px 14px',
                    fontSize: '1rem',
                    fontWeight: 700,
                    color: 'var(--text-muted)',
                    backgroundColor: 'var(--bg-secondary, var(--bg-tertiary))',
                    borderRight: '1px solid var(--border-primary)',
                    display: 'flex',
                    alignItems: 'center',
                    flexShrink: 0,
                    lineHeight: 1,
                  }}>
                    GHS
                  </span>
                  <input
                    type="number"
                    className="settlement-amount-input"
                    style={{ border: 'none', borderRadius: 0, paddingLeft: '16px', flex: 1, outline: 'none', backgroundColor: 'transparent' }}
                    min="0"
                    step="0.01"
                    placeholder="0.00"
                    value={requestedAmount}
                    onChange={(e) => setRequestedAmount(e.target.value)}
                    disabled={!settlementType || isRefreshingBalance}
                  />
                </div>
              )}
            </div>

            {requestedAmount && feeData && !isCheckingFee && (
              <div className="fee-summary" style={{
                marginTop: '16px',
                padding: '12px',
                backgroundColor: 'var(--bg-tertiary)',
                borderRadius: '12px',
                fontSize: '0.9rem',
                display: 'flex',
                flexDirection: 'column',
                gap: '8px'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span style={{ color: 'var(--text-muted)' }}>{t('serviceFee', { ns: 'settlements', defaultValue: 'Service Fee' })}</span>
                  <span style={{ fontWeight: 600 }}>{formatter.format(Number(feeData.feeApplied || feeData.fee || 0))}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', paddingTop: '8px', borderTop: '1px solid var(--border-primary)' }}>
                  <span style={{ fontWeight: 700 }}>{t('totalDebit', { ns: 'settlements', defaultValue: 'Total Debit' })}</span>
                  <span style={{ fontWeight: 800, color: 'var(--accent)' }}>{formatter.format(Number(feeData.total || feeData.totalPayable || 0))}</span>
                </div>
              </div>
            )}

            <button
              type="submit"
              className="settlement-submit-btn"
              disabled={
                (settlementType === 'partial' && (!requestedAmount || parseFloat(requestedAmount) <= 0)) ||
                !settlementType ||
                isRefreshingBalance ||
                isSubmitting
              }
            >
              <span className="material-symbols-outlined">payments</span>
              {isSubmitting
                ? t('calculatingFee', { ns: 'settlements', defaultValue: 'Calculating fee...' })
                : t('confirmSettlement', { ns: 'settlements', defaultValue: 'Confirm Settlement' })}
            </button>
            
            {primaryAccount && (
              <p style={{ textAlign: 'center', fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '12px' }}>
                {t('settlingTo', { ns: 'settlements', defaultValue: 'Settling to' })} <strong>{formatAccountDisplay(primaryAccount)?.label}</strong>
              </p>
            )}
          </form>
        </aside>
      </div>

      {isConfirmOpen && pendingRequest && (
        <div className="settlement-confirm-overlay" role="dialog" aria-modal="true">
          <div className="settlement-confirm-modal">
            <h3>{t('confirmSettlement', { ns: 'settlements' })}</h3>
            <p>
              {t('confirmSettlementMessage', {
                ns: 'settlements',
                type: pendingRequest.settlementType === 'partial'
                  ? t('partialPayoutText', { ns: 'settlements' })
                  : t('fullPayoutText', { ns: 'settlements' }),
                method: methodLabels[pendingRequest.method] || pendingRequest.method,
              })}
            </p>

            <div className="settlement-confirm-grid">
              <div>
                <span className="settlement-confirm-label">{t('amount', { ns: 'settlements' })}</span>
                <span className="settlement-confirm-value">
                  {formatter.format(pendingRequest.amount)}
                </span>
              </div>
              <div>
                <span className="settlement-confirm-label">{t('chargesLabel', { ns: 'settlements' })}</span>
                <span className="settlement-confirm-value">
                  {formatter.format(pendingRequest.charges)}
                </span>
              </div>
            </div>

            <div className="settlement-confirm-actions">
              <button
                type="button"
                className="btn secondary"
                onClick={handleCancelConfirmation}
                disabled={createSettlementMutation.isPending}
              >
                {t('cancel', { ns: 'settlements' })}
              </button>
              <button
                type="button"
                className="btn primary"
                onClick={handleConfirm}
                disabled={createSettlementMutation.isPending}
              >
                {createSettlementMutation.isPending 
                  ? t('processing', { ns: 'settlements', defaultValue: 'Processing...' })
                  : t('confirmPayout', { ns: 'settlements' })}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Settlements;

